import{_ as a,o as t,c as n,O as r}from"./chunks/framework.0d5b6918.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/service-packages.md","filePath":"en/materials/service-packages.md","lastUpdated":1776439080000}'),s={name:"en/materials/service-packages.md"};function i(o,e,l,d,c,p){return t(),n("div",null,e[0]||(e[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Cooperation</p><h1>Kickoff Options / Standard Service Packages</h1><div class="brand-hero__panel"><span class="brand-pill">Service Entry</span><strong>ExecFabric&#39;s current kickoff modes revolve around three project shapes: organizing one real workflow, onboarding governed execution, and delivering a small formal project. The focus is making phase one verifiable, deliverable, and reusable.</strong><p>The key to judging cooperation is not how many feature names exist. It is whether the current scenario is clear, whether the boundary is clear, and whether phase one can produce a stable result.</p></div><p class="brand-lead"> The more common starting point is not customizing a giant platform immediately. It is taking <strong>one high-frequency, repeatable workflow with relatively clear rules</strong> and building the smallest closed loop around it first. That is easier to evaluate for ROI and easier to extend later. </p><p class="brand-lead"> This page answers &quot;when should the conversation move into project delivery.&quot; It does not mean every user should buy a service package next. If the other side is still in the free path, local script-slot expansion, or the standard team monthly or annual path, prioritize the membership and billing route first. Move to this page only when stronger isolation, intranet access, local bridging, or formal project boundaries have entered the discussion. </p><p class="brand-lead"> The public experience flow, the standard team path, formal delivery, and private deployment should currently be explained as distinct routes, so different customers can find the right entry quickly. </p><div class="brand-chip-list"><span class="brand-chip">Start with one point</span><span class="brand-chip">Close scope early</span><span class="brand-chip">Fit real scenarios</span><span class="brand-chip">Support formal delivery</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/en/contact.html#lead-form">Discuss a specific scenario</a><a class="cta-button" href="../product/editions.html">View the edition roadmap</a><a class="cta-button" href="../product/implementation-training.html">View Implementation &amp; Training Services</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // SERVICE PACKAGES</span><span>MAT 04</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">one painful flow first</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">delivery</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">controlled execution</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">delivery_value</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">repeatable_solution</span></span></div><div class="matrix-panel__callout">DON&#39;T START WITH A BIG EMPTY SYSTEM</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">status</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">open</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">real scenarios</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">style</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">small first</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Package A</p><h2>Workflow automation starter</h2><p>Best for high-frequency repeatable flows such as report consolidation, data cleaning, file processing, and import / export work where one painful point should be stabilized first.</p><ul class="brand-list"><li>Close scope around one painful workflow first</li><li>Prioritize proving actual time savings</li><li>Well suited to pilot projects and phase-one validation</li></ul></article><article class="brand-card"><p class="brand-kicker">Package B</p><h2>Script onboarding and governance package</h2><p>Best for environments where scripts or ops actions already exist but there is still no unified entry, no pre-execution confirmation, no clear history, and no governance boundary.</p><ul class="brand-list"><li>Script / Skill onboarding</li><li>Pre-execution confirmation and risk grading</li><li>Visible history and failure reasons</li></ul></article><article class="brand-card"><p class="brand-kicker">Package C</p><h2>Small private-deployment delivery package</h2><p>Best for scenarios that have moved beyond the standard team edition and now need stronger isolation, local data or local script access, stricter governance requirements, and formal 1.0 enterprise single-tenant delivery.</p><ul class="brand-list"><li>Independent tenants and explicit permission boundaries</li><li>Local execution bridge plus audit</li><li>Support for formal project delivery</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Entry Split</p><h2>Which situations should not be pushed straight into project delivery</h2><table class="cooperation-start-table"><thead><tr><th>Current state</th><th>Better path first</th><th>Why</th></tr></thead><tbody><tr><td>Still touching the platform for the first time</td><td>Start with the free path</td><td>First confirm whether this is even worth understanding further instead of rushing into a project quote</td></tr><tr><td>Only continuing personal script onboarding</td><td>Start with local script-slot expansion</td><td>This is lightweight expansion, not formal team collaboration or enterprise delivery</td></tr><tr><td>Multi-user collaboration has started, but the requirement is still fairly standard</td><td>Use the standard team monthly or annual tenant path first</td><td>Validate collaboration through the standard SaaS route first, then decide whether heavier delivery is really necessary</td></tr><tr><td>Stronger isolation, intranet access, local bridging, or formal acceptance is required</td><td>Move into project-delivery discussion</td><td>This is the point where deployment, delivery boundary, milestones, and service packages actually matter</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Good Fit</p><h2>Project types that are better to prioritize right now</h2><ul class="brand-list"><li>High-frequency reporting, file, and data-processing workflows</li><li>Environments that already have Python scripts and need one unified entry</li><li>Local environments, local scripts, or intranet resources that need governed scheduling</li><li>Cases where the standard team edition is no longer enough and stronger isolation, custom pages, or formal delivery boundaries are needed</li></ul></article><article class="brand-card"><p class="brand-kicker">Not A Good Start</p><h2>Things that should not be started directly right now</h2><ul class="brand-list"><li>A huge all-in-one platform customization with no clear phase-one boundary</li><li>Each customer demanding deep customization while no reuse space or out-of-scope line exists</li><li>Default full-repository source delivery while still expecting the platform to remain reusable and upgradeable later</li><li>An &quot;AI chat shell&quot; with no real execution scenario behind it</li><li>Very low budget combined with an expectation of long-term resident support</li><li>No scripts, no workflows, and no concrete problem to solve, but still wanting to build a large system first</li></ul></article></section><section class="brand-card"><p class="brand-kicker">How We Start</p><h2>Standard kickoff method</h2><table class="cooperation-start-table"><thead><tr><th>Step</th><th>What happens</th><th>Purpose</th></tr></thead><tbody><tr><td>01</td><td>Name the most painful workflow clearly first</td><td>Avoid making the requirement too large and too vague from the start</td></tr><tr><td>02</td><td>Explain the current inputs, outputs, and execution frequency</td><td>Judge whether that point is worth automating first</td></tr><tr><td>03</td><td>Close scope, timeline, and out-of-scope items around one point</td><td>Produce a formal proposal and quote quickly</td></tr><tr><td>04</td><td>Deliver the minimal closed loop first, then decide the second phase</td><td>Reduce decision complexity and make reuse cases easier to form</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Cooperation Ladder</p><h2>How to choose among the five current cooperation modes</h2><table class="cooperation-start-table"><thead><tr><th>Cooperation mode</th><th>Best for whom</th><th>What it is better suited to solve now</th><th>What it does not mean by default</th></tr></thead><tbody><tr><td>Free demo</td><td>People who are learning the platform for the first time</td><td>Confirm the execution chain, product position, and whether the platform is worth exploring further</td><td>Not a formal enterprise production environment</td></tr><tr><td>Paid consultation / POC</td><td>Teams that already have a scenario but have not closed the scope yet</td><td>Clarify the goal, scope, budget, and implementation order first</td><td>Not a full formal delivery or unlimited rounds of requirement discussion</td></tr><tr><td>Team-edition SaaS</td><td>Teams that need standard capabilities, lighter collaboration, and lower budget</td><td>Enter formal usage and standard team collaboration at a lower threshold</td><td>Not isolated private deployment or a deep custom project</td></tr><tr><td>Lightweight private deployment</td><td>Small teams that want one formal isolated environment first</td><td>Run one formal closed loop with a smaller scope</td><td>Not complex custom development or long-term resident support</td></tr><tr><td>Standard private deployment</td><td>Customers that need intranet deployment, compliance, stronger boundaries, and formal acceptance</td><td>Carry isolated deployment, formal training, and long-term baseline support</td><td>Not unlimited new features or unlimited support by default</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Implementation</p><h2>How implementation and training are arranged right now</h2><ul class="brand-list"><li>Projects are usually pushed in five steps: scope confirmation, environment preparation, capability onboarding, joint testing and acceptance, then training and go-live.</li><li>Training is role-based instead of turning business owners, admins, general users, and IT operations into one oversized class.</li><li>Go-live does not mean handing over just one account. It also includes usage notes, delivery notes, hot-update notes, and result-entry notes.</li></ul></article><article class="brand-card"><p class="brand-kicker">Support Boundary</p><h2>Clarify the follow-up support boundary early</h2><ul class="brand-list"><li>Troubleshooting inside the delivered scope, baseline Q&amp;A, and a small amount of script updates usually belong to standard support.</li><li>New features, large page redesigns, deep third-party integrations, and resident support should be evaluated separately.</li><li>The current default assumption is a workday support window. Higher response levels should be agreed separately.</li></ul><p><a href="../product/implementation-training.html">View Implementation &amp; Training Services</a></p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why This Structure</p><h2>The direct value of this cooperation structure</h2><ul class="brand-list"><li>The phase-one boundary is clearer, which makes evaluation and acceptance easier</li><li>It is easier to see a real result in a shorter cycle</li><li>You can validate workflow value first, then decide whether a second-phase expansion is worth it</li><li>It works well for cases that are growing from the standard team edition into enterprise or private deployment</li></ul></article><article class="brand-card"><p class="brand-kicker">Preparation</p><h2>What is useful to prepare before evaluation begins</h2><ul class="brand-list"><li>One real workflow name and the current most painful step</li><li>Inputs, outputs, execution frequency, and the current handling method</li><li>Existing scripts, sample files, interface notes, or execution rules</li><li>The result and timeline you want from phase one</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>Bring one real workflow into evaluation for a faster discussion</h2><p class="brand-lead">Once the conversation becomes concrete, the focus usually should not stay on abstract concepts. It should move quickly into scope, inputs and outputs, cycle length, and the phase-one objective.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./membership-benefits-pricing.html"><span>Pricing</span><strong>See the membership and pricing path first</strong></a><a class="brand-link-card" href="/en/contact.html#lead-form"><span>Lead</span><strong>Discuss a real scenario</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>Customer Delivery &amp; Usage</strong></a><a class="brand-link-card" href="../product/implementation-training.html"><span>Training</span><strong>Implementation &amp; Training Services</strong></a><a class="brand-link-card" href="./source-delivery-boundaries.html"><span>Boundary</span><strong>Source &amp; Authorization Boundaries</strong></a><a class="brand-link-card" href="../product/onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>Edition Roadmap</strong></a></div></div></section></div>',1)]))}const m=a(s,[["render",i]]);export{u as __pageData,m as default};
